const certificatesData = [
  {
    id: 1,
    name: "李明",
    course: "商业管理硕士 (MBA)",
    date: "2023-06-15",
    certificateId: "SIU-MBA-2023-001",
    image: "/images/certificates/mba-certificate.svg"
  },
  {
    id: 2,
    name: "张伟",
    course: "人工智能与数据科学",
    date: "2023-07-20",
    certificateId: "SIU-AI-2023-042",
    image: "/images/certificates/ai-certificate.svg"
  },
  {
    id: 3,
    name: "王芳",
    course: "全球卫生与医疗管理",
    date: "2023-05-10",
    certificateId: "SIU-GH-2023-019",
    image: "/images/certificates/health-certificate.svg"
  },
  {
    id: 4,
    name: "赵强",
    course: "国际金融与投资",
    date: "2023-08-25",
    certificateId: "SIU-FIN-2023-007",
    image: "/images/certificates/certificate-template.svg"
  },
  {
    id: 5,
    name: "刘洋",
    course: "可持续发展与环境管理",
    date: "2023-04-30",
    certificateId: "SIU-ENV-2023-015",
    image: "/images/certificates/certificate-template.svg"
  },
  {
    id: 6,
    name: "陈红",
    course: "跨文化交流与全球公民",
    date: "2023-09-12",
    certificateId: "SIU-CC-2023-029",
    image: "/images/certificates/certificate-template.svg"
  }
];

const CertificatesPage = () => {
  const { t } = useTranslation();
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCertificate, setSelectedCertificate] = useState(null);
  const [processedCertificates, setProcessedCertificates] = useState([]);

  // 处理SVG证书
  useEffect(() => {
    // 为每个证书创建处理后的图像URL
    const processCertificates = async () => {
      const processed = await Promise.all(
        certificatesData.map(async (cert) => {
          try {
            // 获取SVG模板
            const response = await fetch(cert.image);
            if (!response.ok) throw new Error('Failed to load certificate template');
            
            let svgText = await response.text();
            
            // 替换占位符
            svgText = svgText.replace('[RECIPIENT NAME]', cert.name);
            svgText = svgText.replace('[DATE]', cert.date);
            svgText = svgText.replace('[CERTIFICATE-ID]', cert.certificateId);
            svgText = svgText.replace('[PROGRAM/DEGREE]', cert.course);
            svgText = svgText.replace('[HASH]', 'SIU-' + Math.random().toString(36).substring(2, 10).toUpperCase());
            
            // 创建Blob和URL
            const blob = new Blob([svgText], { type: 'image/svg+xml' });
            const url = URL.createObjectURL(blob);
            
            return { ...cert, processedImage: url };
          } catch (error) {
            console.error('Error processing certificate:', error);
            return { ...cert, processedImage: cert.image };
          }
        })
      );
      
      setProcessedCertificates(processed);
    };
    
    processCertificates();
    
    // 清理函数
    return () => {
      // 释放创建的对象URL
      processedCertificates.forEach(cert => {
        if (cert.processedImage && cert.processedImage.startsWith('blob:')) {
          URL.revokeObjectURL(cert.processedImage);
        }
      });
    };
  }, []);
  
  // 搜索筛选逻辑
  const filteredCertificates = processedCertificates.filter(cert =>
    cert.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    cert.course.toLowerCase().includes(searchTerm.toLowerCase()) ||
    cert.certificateId.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // 选择证书查看详情
  const handleCertificateClick = (certificate) => {
    setSelectedCertificate(certificate);
  };

  // 关闭证书详情模态框
  const closeModal = () => {
    setSelectedCertificate(null);
  };

  return (
    <div className="bg-gray-50 min-h-screen py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* 标题部分 */}
        <div className="text-center mb-12">
          <h1 className="text-3xl font-extrabold text-gray-900 sm:text-4xl">{t('certificatesPage.title')}</h1>
          <p className="mt-3 max-w-2xl mx-auto text-xl text-gray-500 sm:mt-4">
            {t('certificatesPage.subtitle')}
          </p>
        </div>

        {/* 搜索框 */}
        <div className="max-w-xl mx-auto mb-10">
          <div className="relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <svg className="h-5 w-5 text-gray-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
            <input
              type="text"
              className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md leading-5 bg-white shadow-sm focus:outline-none focus:ring-[#003087] focus:border-[#003087]"
              placeholder={t('certificatesPage.searchPlaceholder')}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* 证书展示区域 */}
        <div className="grid grid-cols-1 gap-8 sm:grid-cols-2 lg:grid-cols-3">
          {filteredCertificates.map((certificate) => (
            <button
              key={certificate.id}
              className="bg-white overflow-hidden shadow rounded-lg cursor-pointer transform transition duration-300 hover:shadow-lg hover:scale-105 text-left w-full border-0 p-0 focus:outline-none focus:ring-2 focus:ring-[#003087]"
              onClick={() => handleCertificateClick(certificate)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                  handleCertificateClick(certificate);
                }
              }}
              aria-label={t('certificatesPage.ariaLabel', { name: certificate.name, course: certificate.course })}
            >
              <div className="h-48 bg-gray-200 overflow-hidden">
                <img
                  src={certificate.processedImage || certificate.image}
                  alt={`${certificate.name}的${certificate.course}证书`}
                  className="w-full h-full object-cover"
                />
              </div>
              <div className="p-6">
                <h3 className="text-lg font-medium text-gray-900">{certificate.name}</h3>
                <p className="mt-1 text-sm text-gray-500">{certificate.course}</p>
                <div className="mt-4 flex justify-between items-center">
                  <span className="text-xs text-gray-500">{t('certificatesPage.certificateModal.issueDate')}: {certificate.date}</span>
                  <span className="text-xs font-medium text-[#003087]">{certificate.certificateId}</span>
                </div>
              </div>
            </button>
          ))}
        </div>

        {/* 无结果提示 */}
        {filteredCertificates.length === 0 && (
          <div className="text-center py-12">
            <svg className="mx-auto h-12 w-12 text-gray-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <h3 className="mt-2 text-lg font-medium text-gray-900">{t('certificatesPage.noResultsTitle')}</h3>
            <p className="mt-1 text-sm text-gray-500">{t('certificatesPage.noResultsText')}</p>
          </div>
        )}

        {/* 验证证书区域 */}
        <div 
          className="mt-16 bg-[#003087] rounded-lg shadow-lg overflow-hidden" 
          style={{ backgroundColor: '#003087' }}
        >
          <div className="px-6 py-8 sm:p-10 sm:pb-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-center">
              <div>
                <h3 
                  className="text-2xl leading-8 font-extrabold text-white tracking-tight"
                  style={{ color: 'white' }}
                >
                  {t('certificatesPage.verifySection.title')}
                </h3>
                <p 
                  className="mt-4 text-lg text-white"
                  style={{ color: 'white' }}
                >
                  {t('certificatesPage.verifySection.description')}
                </p>
                <div className="mt-6">
                  <Link
                    to="/verify-certificate"
                    className="inline-flex items-center px-6 py-3 border border-transparent text-base font-medium rounded-md shadow-sm text-[#003087] bg-white hover:bg-gray-50"
                    style={{ backgroundColor: 'white', color: '#003087' }}
                  >
                    {t('certificatesPage.verifySection.action')}
                  </Link>
                </div>
              </div>
              <div className="hidden md:flex justify-center">
                <svg 
                  className="h-48 w-auto text-white" 
                  xmlns="http://www.w3.org/2000/svg" 
                  fill="none" 
                  viewBox="0 0 24 24" 
                  stroke="currentColor"
                  style={{ opacity: 0.8 }}
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                </svg>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* 证书详情模态框 */}
      {selectedCertificate && (
        <div className="fixed inset-0 overflow-y-auto z-50" aria-labelledby="modal-title" role="dialog" aria-modal="true">
          <div className="flex items-end justify-center min-h-screen pt-4 px-4 pb-20 text-center sm:block sm:p-0">
            <div 
              className="fixed inset-0 bg-gray-500 bg-opacity-75 transition-opacity" 
              aria-hidden="true" 
              onClick={closeModal}
              role="button"
              tabIndex={0}
              onKeyDown={(e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                  closeModal();
                }
              }}
            ></div>

            <span className="hidden sm:inline-block sm:align-middle sm:h-screen" aria-hidden="true">&#8203;</span>

            <div className="inline-block align-bottom bg-white rounded-lg text-left overflow-hidden shadow-xl transform transition-all sm:my-8 sm:align-middle sm:max-w-3xl sm:w-full">
              <div className="bg-white">
                <div className="relative">
                  <img
                    src={selectedCertificate.processedImage || selectedCertificate.image}
                    alt={`${selectedCertificate.name}的${selectedCertificate.course}证书`}
                    className="w-full h-auto"
                  />
                  <button
                    type="button"
                    className="absolute top-4 right-4 bg-white rounded-full p-1 shadow-md hover:bg-gray-100"
                    onClick={closeModal}
                    aria-label={t('certificatesPage.certificateModal.close')}
                  >
                    <svg className="h-6 w-6 text-gray-900" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
                <div className="p-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <h3 className="text-lg font-bold text-gray-900">{t('certificatesPage.certificateModal.studentInfo')}</h3>
                      <p className="mt-2 text-gray-600">{t('certificatesPage.certificateModal.name')}: {selectedCertificate.name}</p>
                    </div>
                    <div>
                      <h3 className="text-lg font-bold text-gray-900">{t('certificatesPage.certificateModal.certificateDetails')}</h3>
                      <p className="mt-2 text-gray-600">{t('certificatesPage.certificateModal.course')}: {selectedCertificate.course}</p>
                      <p className="mt-1 text-gray-600">{t('certificatesPage.certificateModal.issueDate')}: {selectedCertificate.date}</p>
                      <p className="mt-1 text-gray-600">{t('certificatesPage.certificateModal.certificateId')}: {selectedCertificate.certificateId}</p>
                    </div>
                  </div>
                  <div className="mt-6 flex justify-between">
                    <a
                      href="#download"
                      onClick={(e) => {
                        e.preventDefault();
                        // 下载证书逻辑
                        const link = document.createElement('a');
                        link.href = selectedCertificate.processedImage || selectedCertificate.image;
                        link.download = `${selectedCertificate.name}-${selectedCertificate.course}-${selectedCertificate.certificateId}.svg`;
                        document.body.appendChild(link);
                        link.click();
                        document.body.removeChild(link);
                      }}
                      className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-[#003087] hover:bg-blue-900"
                    >
                      {t('certificatesPage.certificateModal.download')}
                    </a>
                    <button
                      type="button"
                      onClick={closeModal}
                      className="inline-flex items-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50"
                    >
                      {t('certificatesPage.certificateModal.close')}
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CertificatesPage;
